package main

import (
	"context"
	"errors"
	"fmt"
	"strings"
	"time"

	"github.com/dop251/goja"
)

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with order fields injected as global variables, and returns the resulting discount amount.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	// Validate script for potentially dangerous operations
	if containsDangerousOperations(script) {
		return 0.0, errors.New("script contains forbidden operations")
	}

	// Create a new VM
	vm := goja.New()

	// Create a context with timeout
	ctx, cancel := context.WithTimeout(context.Background(), 100*time.Millisecond)
	defer cancel()

	// Prepare the execution with context
	program, err := goja.Compile("", script, false)
	if err != nil {
		return 0.0, fmt.Errorf("script compilation error: %w", err)
	}

	// Sanitize order data before injection to ensure only allowed types are passed
	sanitizedOrder := sanitizeOrderData(order)

	// Inject sanitized order fields as global variables in the VM
	for key, value := range sanitizedOrder {
		vm.Set(key, value)
	}

	// Execute the script with a goroutine to handle timeout
	resultChan := make(chan goja.Value, 1)
	errChan := make(chan error, 1)

	go func() {
		result, err := vm.RunProgram(program)
		if err != nil {
			errChan <- err
			return
		}
		resultChan <- result
	}()

	select {
	case result := <-resultChan:
		// Convert result to float64
		discount, ok := result.Export().(float64)
		if !ok {
			// Try to convert from other numeric types (e.g., int, float32)
			switch v := result.Export().(type) {
			case int:
				discount = float64(v)
			case int32:
				discount = float64(v)
			case int64:
				discount = float64(v)
			case float32:
				discount = float64(v)
			case uint:
				discount = float64(v)
			case uint32:
				discount = float64(v)
			case uint64:
				discount = float64(v)
			default:
				return 0.0, fmt.Errorf("script must return a number, got %T", result.Export())
			}
		}
		return discount, nil
	case err := <-errChan:
		return 0.0, fmt.Errorf("script execution error: %w", err)
	case <-ctx.Done():
		return 0.0, errors.New("script execution timed out")
	}
}

// containsDangerousOperations checks if the script contains potentially dangerous operations
func containsDangerousOperations(script string) bool {
	dangerousPatterns := []string{
		"import",
		"require",
		"eval",
		"Function",
		"constructor",
		"__proto__",
		"prototype",
		"global",
		"window",
		"document",
		"process",
		"console.log",
		"console.",
		"setTimeout",
		"setInterval",
		"XMLHttpRequest",
		"fetch",
		"File",
		"FileSystem",
		"fs.",
		"os.",
		"exec",
		"spawn",
		"child_process",
	}

	scriptLower := strings.ToLower(script)
	for _, pattern := range dangerousPatterns {
		if strings.Contains(scriptLower, pattern) {
			return true
		}
	}
	return false
}

// sanitizeOrderData ensures that only safe data types are passed to the VM
func sanitizeOrderData(order map[string]interface{}) map[string]interface{} {
	sanitized := make(map[string]interface{})

	for k, v := range order {
		switch val := v.(type) {
		case string, int, int32, int64, uint, uint32, uint64, float32, float64, bool:
			// These are safe primitive types
			sanitized[k] = val
		case nil:
			// Allow nil values
			sanitized[k] = val
		case map[string]interface{}:
			// Recursively sanitize nested maps
			sanitized[k] = sanitizeOrderData(val)
		default:
			// For any other type, convert to string or ignore
			sanitized[k] = fmt.Sprintf("%v", val)
		}
	}

	return sanitized
}

