import (
	"errors"
	"fmt"
	"time"

	"github.com/dop251/goja"
)

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with order fields injected as global variables, and returns the resulting discount amount.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// Set up a time-limited execution environment
	done := make(chan struct{})
	go func() {
		select {
		case <-time.After(100 * time.Millisecond): // Limit execution to 100ms
			vm.Interrupt("script execution timeout")
		case <-done:
		}
	}()
	defer close(done)

	// Create a safe sandboxed environment by not directly injecting user data as globals
	// Instead, provide a controlled interface to access order data
	orderObj := vm.NewObject()
	for key, value := range order {
		err := orderObj.Set(key, value)
		if err != nil {
			return 0.0, fmt.Errorf("failed to set order property: %w", err)
		}
	}

	// Make the order object available in the VM through a safe variable
	err := vm.Set("order", orderObj)
	if err != nil {
		return 0.0, fmt.Errorf("failed to set order in VM: %w", err)
	}

	// Prevent access to dangerous properties/functions by removing them from the global
	deleteBuiltinFuncs(vm)

	// Execute the script
	result, err := vm.RunString(script)
	if err != nil {
		var interruptErr *goja.InterruptedError
		if errors.As(err, &interruptErr) {
			return 0.0, fmt.Errorf("script execution timeout: %w", err)
		}
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Convert result to float64
	exported := result.Export()
	switch v := exported.(type) {
	case float64:
		return v, nil
	case float32:
		return float64(v), nil
	case int:
		return float64(v), nil
	case int32:
		return float64(v), nil
	case int64:
		return float64(v), nil
	case uint:
		return float64(v), nil
	case uint32:
		return float64(v), nil
	case uint64:
		return float64(v), nil
	default:
		return 0.0, fmt.Errorf("script must return a number, got %T", exported)
	}
}

// deleteBuiltinFuncs removes potentially dangerous functions from the VM's global scope
func deleteBuiltinFuncs(vm *goja.Runtime) {
	dangerousGlobals := []string{
		"load",      // Can load external files
		"print",     // Could be used for information disclosure
		"gc",        // Garbage collection control
		"reference", // Could reference dangerous objects
	}

	for _, name := range dangerousGlobals {
		vm.GlobalObject().Delete(name)
	}
}

